import React, { useState, useEffect } from 'react';
import styled from 'styled-components';
import { BarChart3, TrendingUp, Users, DollarSign, Zap } from 'lucide-react';
import AISampleChart from '../charts/AISampleChart';

const DashboardContainer = styled.div`
  padding: 1.5rem;
`;

const DashboardHeader = styled.div`
  margin-bottom: 2rem;
`;

const DashboardTitle = styled.h1`
  font-size: 1.75rem;
  font-weight: 700;
  color: #1e293b;
  margin: 0 0 0.5rem 0;
`;

const DashboardSubtitle = styled.p`
  color: #64748b;
  margin: 0;
`;

const StatsGrid = styled.div`
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(240px, 1fr));
  gap: 1.5rem;
  margin-bottom: 2rem;
`;

const StatCard = styled.div`
  background: white;
  border-radius: 1rem;
  padding: 1.5rem;
  box-shadow: 0 4px 15px rgba(0, 0, 0, 0.05);
  border: 1px solid #e2e8f0;
  display: flex;
  flex-direction: column;
`;

const StatHeader = styled.div`
  display: flex;
  justify-content: space-between;
  align-items: center;
  margin-bottom: 1rem;
`;

const StatIcon = styled.div`
  width: 3rem;
  height: 3rem;
  border-radius: 0.75rem;
  display: flex;
  align-items: center;
  justify-content: center;
  background: ${props => props.color || '#3b82f6'};
  color: white;
`;

const StatTitle = styled.h3`
  font-size: 0.875rem;
  font-weight: 500;
  color: #64748b;
  margin: 0;
`;

const StatValue = styled.div`
  font-size: 1.75rem;
  font-weight: 700;
  color: #1e293b;
  margin-bottom: 0.25rem;
`;

const StatChange = styled.div`
  font-size: 0.875rem;
  color: ${props => props.positive ? '#10b981' : '#ef4444'};
  display: flex;
  align-items: center;
  gap: 0.25rem;
`;

const ChartsGrid = styled.div`
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(500px, 1fr));
  gap: 1.5rem;
  
  @media (max-width: 768px) {
    grid-template-columns: 1fr;
  }
`;

const AIDashboard = () => {
  const [chartConfigs, setChartConfigs] = useState([]);
  
  // Sample chart configurations that would be generated by AI
  const sampleChartConfigs = [
    {
      id: 1,
      title: "Monthly Revenue Growth",
      type: "line",
      data: {
        labels: ['Jan', 'Feb', 'Mar', 'Apr', 'May', 'Jun'],
        datasets: [
          {
            label: 'Revenue ($)',
            data: [12000, 19000, 15000, 18000, 22000, 25000],
            borderColor: 'rgb(59, 130, 246)',
            backgroundColor: 'rgba(59, 130, 246, 0.5)',
          },
        ],
      },
      insights: [
        "Revenue increased by 108% from January to June",
        "Highest growth occurred between April and May",
        "Consistent upward trend indicates healthy business growth"
      ]
    },
    {
      id: 2,
      title: "User Engagement Metrics",
      type: "bar",
      data: {
        labels: ['Mon', 'Tue', 'Wed', 'Thu', 'Fri', 'Sat', 'Sun'],
        datasets: [
          {
            label: 'Active Users',
            data: [1200, 1900, 1300, 1500, 1800, 2200, 2500],
            backgroundColor: 'rgba(16, 185, 129, 0.5)',
            borderColor: 'rgb(16, 185, 129)',
            borderWidth: 1,
          },
        ],
      },
      insights: [
        "Weekend engagement is 38% higher than weekdays",
        "Friday shows peak user activity",
        "Consistent daily active users averaging 1,800"
      ]
    },
    {
      id: 3,
      title: "Product Category Distribution",
      type: "pie",
      data: {
        labels: ['Electronics', 'Clothing', 'Home Goods', 'Books', 'Sports'],
        datasets: [
          {
            data: [35, 25, 20, 12, 8],
            backgroundColor: [
              'rgba(59, 130, 246, 0.8)',
              'rgba(16, 185, 129, 0.8)',
              'rgba(245, 158, 11, 0.8)',
              'rgba(139, 92, 246, 0.8)',
              'rgba(239, 68, 68, 0.8)',
            ],
            borderColor: [
              'rgb(59, 130, 246)',
              'rgb(16, 185, 129)',
              'rgb(245, 158, 11)',
              'rgb(139, 92, 246)',
              'rgb(239, 68, 68)',
            ],
            borderWidth: 1,
          },
        ],
      },
      insights: [
        "Electronics category dominates with 35% market share",
        "Books and Sports categories show growth potential",
        "Balanced distribution across all product categories"
      ]
    }
  ];
  
  useEffect(() => {
    // In a real implementation, this would fetch AI-generated chart configs
    setChartConfigs(sampleChartConfigs);
  }, []);
  
  const statCards = [
    {
      title: "Total Revenue",
      value: "$45,231",
      change: "+20.1%",
      icon: <DollarSign size={20} />,
      color: "linear-gradient(135deg, #10b981 0%, #059669 100%)",
      changePositive: true
    },
    {
      title: "Active Users",
      value: "2,350",
      change: "+18.1%",
      icon: <Users size={20} />,
      color: "linear-gradient(135deg, #3b82f6 0%, #2563eb 100%)",
      changePositive: true
    },
    {
      title: "Conversion Rate",
      value: "4.2%",
      change: "+2.1%",
      icon: <TrendingUp size={20} />,
      color: "linear-gradient(135deg, #8b5cf6 0%, #7c3aed 100%)",
      changePositive: true
    },
    {
      title: "Avg. Response Time",
      value: "1.2s",
      change: "-12.4%",
      icon: <Zap size={20} />,
      color: "linear-gradient(135deg, #f59e0b 0%, #d97706 100%)",
      changePositive: true
    }
  ];

  return (
    <DashboardContainer>
      <DashboardHeader>
        <DashboardTitle>AI-Powered Analytics Dashboard</DashboardTitle>
        <DashboardSubtitle>Real-time insights generated by AI</DashboardSubtitle>
      </DashboardHeader>
      
      <StatsGrid>
        {statCards.map((stat, index) => (
          <StatCard key={index}>
            <StatHeader>
              <StatTitle>{stat.title}</StatTitle>
              <StatIcon style={{ background: stat.color }}>
                {stat.icon}
              </StatIcon>
            </StatHeader>
            <StatValue>{stat.value}</StatValue>
            <StatChange positive={stat.changePositive}>
              {stat.change}
            </StatChange>
          </StatCard>
        ))}
      </StatsGrid>
      
      <ChartsGrid>
        {chartConfigs.map((config) => (
          <AISampleChart
            key={config.id}
            title={config.title}
            chartConfig={{
              type: config.type,
              data: config.data,
              options: {
                responsive: true,
                plugins: {
                  legend: {
                    position: 'top',
                  },
                  title: {
                    display: true,
                    text: config.title,
                  },
                },
              }
            }}
            insights={config.insights}
          />
        ))}
      </ChartsGrid>
    </DashboardContainer>
  );
};

export default AIDashboard;
